    @Test
    fun `parseSourcesToFileScheme - handles real fragments if file does not exist`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val filename = "image.png"
        val content = """<img src="$filename#fragment">"""

        // We simulate that "image.png#fragment" does NOT exist, but "image.png" DOES exist?
        // Actually, we just need to ensure that if "image.png#fragment" doesn't exist,
        // it falls back to "image.png" as the path, and keeps "fragment" as fragment?
        // Wait, my implementation truncates the fragment if the file doesn't exist.

        // Original behavior:
        // path = "image.png" (from attrUri.path)
        // Paths.get -> .../image.png
        // URI -> file:///.../image.png
        // The fragment is LOST in the new URI because getFileUri only takes path!

        // Let's verify if getFileUri loses the fragment.
        // getFileUri returns URI("file", p, null). Fragment is null.

        // So currently, AnkiDroid STRIPS fragments from local file URIs.
        // My change doesn't make it worse. It just allows capturing the # as part of path if file exists.
        // If file doesn't exist, it behaves as before (using attrUri.path, losing fragment).

        val result = parseSourcesToFileScheme(content, mediaDir) {
            it.name == "image.png#fragment" // Returns false
        }

        // Expected: fragment is stripped (same as current behavior)
        // file:///.../image.png
        assert(result.contains("image.png"))
        assert(!result.contains("%23fragment"))
        assert(!result.contains("#fragment"))
    }
}
